mutation DraftOrderCalculateValidationAndShippingRates(
  $emptyLineItems: DraftOrderInput!
  $invalidEmail: DraftOrderInput!
  $availableShippingRatesEmpty: DraftOrderInput!
  $availableShippingRatesNoMatch: DraftOrderInput!
  $availableShippingRatesMatching: DraftOrderInput!
  $paymentTermsTemplateId: DraftOrderInput!
) {
  emptyLineItems: draftOrderCalculate(input: $emptyLineItems) {
    calculatedDraftOrder {
      currencyCode
    }
    userErrors {
      field
      message
    }
  }
  invalidEmail: draftOrderCalculate(input: $invalidEmail) {
    calculatedDraftOrder {
      currencyCode
    }
    userErrors {
      field
      message
    }
  }
  availableShippingRatesEmpty: draftOrderCalculate(input: $availableShippingRatesEmpty) {
    calculatedDraftOrder {
      availableShippingRates {
        handle
        title
        price {
          amount
          currencyCode
        }
      }
    }
    userErrors {
      field
      message
    }
  }
  availableShippingRatesNoMatch: draftOrderCalculate(input: $availableShippingRatesNoMatch) {
    calculatedDraftOrder {
      availableShippingRates {
        handle
        title
        price {
          amount
          currencyCode
        }
      }
    }
    userErrors {
      field
      message
    }
  }
  availableShippingRatesMatching: draftOrderCalculate(input: $availableShippingRatesMatching) {
    calculatedDraftOrder {
      availableShippingRates {
        handle
        title
        price {
          amount
          currencyCode
        }
      }
    }
    userErrors {
      field
      message
    }
  }
  paymentTermsTemplateId: draftOrderCalculate(input: $paymentTermsTemplateId) {
    calculatedDraftOrder {
      currencyCode
    }
    userErrors {
      field
      message
    }
  }
}

