upstreamCalls.query:
query OrdersDraftOrderVariantHydrate($id: ID!) {
  productVariant(id: $id) { id title sku taxable price inventoryItem { requiresShipping } product { title } }
}

query OrdersDraftOrderDeliveryProfilesHydrate {
  deliveryProfiles(first: 10) {
    nodes {
      id
      name
      default
      profileItems(first: 10) {
        nodes {
          variants(first: 10) { nodes { id } }
        }
      }
      profileLocationGroups {
        locationGroup {
          id
          locations(first: 10) { nodes { id } }
        }
        locationGroupZones(first: 10) {
          nodes {
            zone {
              id
              countries {
                code { countryCode restOfWorld }
                provinces { code }
              }
            }
            methodDefinitions(first: 10) {
              nodes {
                id
                name
                active
                rateProvider {
                  ... on DeliveryRateDefinition { id price { amount currencyCode } }
                  ... on DeliveryParticipant { id fixedFee { amount currencyCode } percentageOfRateFee }
                }
                methodConditions {
                  id
                  field
                  operator
                  conditionCriteria {
                    __typename
                    ... on MoneyV2 { amount currencyCode }
                    ... on Weight { unit value }
                  }
                }
              }
            }
          }
        }
      }
    }
  }
}

